import{_ as e,c as a,o as s,d as o}from"./app.426dd711.js";const _=JSON.parse('{"title":"5. Pruebas Continuas (Continuous Tests)","description":"","frontmatter":{},"headers":[],"relativePath":"practices/continuous-tests.md"}'),n={name:"practices/continuous-tests.md"},r=o('<h1 id="_5-pruebas-continuas-continuous-tests" tabindex="-1">5. Pruebas Continuas <em>(Continuous Tests)</em> <a class="header-anchor" href="#_5-pruebas-continuas-continuous-tests" aria-hidden="true">#</a></h1><blockquote><p>Las pruebas son las encargadas de verificar el funcionamiento del programa.</p></blockquote><p>Cada ves que se realizan cambios en el programa, estos deben ser sometidos a rigurosas pruebas para garantizar la calidad del sistema. Las pruebas deben ser capaces de verificar el buen funcionamiento de todos los requerimientos solicitados por el usuario. Contando adem\xE1s con las versiones peque\xF1as que se realizan. Hacer pruebas continuas proporciona seguridad en las versiones del software creado, con lo que se puede seguir ampliando el sistema con la certeza de su buen funcionamiento. Siempre es mas f\xE1cil solucionar un problema cuando el c\xF3digo no es muy extenso o cuando se hace cada poco tiempo.</p><p>En esta pr\xE1ctica, podemos encontrar tres tipos de pruebas propuestas:</p><ul><li><p><strong>\u201CPruebas Unitarias\u201D</strong>, consiste en probar el c\xF3digo de manera individual mientras se va programando, en este caso el programador es responsable de su propio desarrollo. No debe esperar a que las pruebas o los procedimientos de aseguramiento de calidad descubran los errores;</p></li><li><p><strong>\u201CPruebas de Aceptaci\xF3n\u201D</strong>, dichas pruebas est\xE1n avocadas al comportamiento funcional del c\xF3digo. A diferencia de las anteriores, son definidas por el usuario y basadas en casos de uso reales que definir\xE1n si la funcionalidad desarrollada cumple con los objetivos esperados;</p></li><li><p><strong>\u201CPruebas de Integraci\xF3n\u201D</strong>, como su nombre lo indica, tienen por objeto, integrar todas las pruebas que conforman la aplicaci\xF3n, a fin de validar el correcto funcionamiento de la misma, evitando que nuevos desarrollos, da\xF1en a los anteriores.</p></li></ul>',5),i=[r];function t(c,d,u,l,p,m){return s(),a("div",null,i)}const f=e(n,[["render",t]]);export{_ as __pageData,f as default};
